using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // --- FormatPhoneNumber ---

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.AreEqual("(555) 123-4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        Assert.StartsWith("(800)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        Assert.EndsWith("1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesPhonePattern()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123", DisplayName = "Too short")]
    [DataRow("12345678901", DisplayName = "Too long")]
    [DataRow("", DisplayName = "Empty")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        var ex = Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));

        Assert.AreEqual("digits", ex.ParamName);
    }

    // --- BuildGreeting ---

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_ReturnsGreetingWithMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.StartsWith("Dear Dr.", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Doe", "Ms.");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_ContainsName()
    {
        var result = _formatter.BuildGreeting("Anderson", "Prof.");

        Assert.Contains("Anderson", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhiteSpace_ThrowsArgumentException(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // --- GenerateSlug ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My Great Post! #1");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleStartingWithLetters_StartsWithExpectedPrefix()
    {
        var result = _formatter.GenerateSlug("Getting Started with C#");

        Assert.StartsWith("getting-started", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleEndingWithWord_EndsWithExpectedSuffix()
    {
        var result = _formatter.GenerateSlug("Introduction to Testing");

        Assert.EndsWith("testing", result);
    }

    [TestMethod]
    [DataRow("  Padded Title  ", "padded-title", DisplayName = "Trims whitespace")]
    [DataRow("ALL CAPS", "all-caps", DisplayName = "Lowercases")]
    [DataRow("dots.and...more", "dots-and-more", DisplayName = "Replaces dots")]
    public void GenerateSlug_VariousInputs_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhiteSpace_ThrowsArgumentException(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // --- FormatCurrency ---

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_EuroSymbol_StartsWithEuro()
    {
        var result = _formatter.FormatCurrency(42.50m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_MatchesCurrencyPattern()
    {
        var result = _formatter.FormatCurrency(1234.56m, "£");

        Assert.MatchesRegex(@"^£\d+\.\d{2}$", result);
    }

    [TestMethod]
    [DataRow(0.0, "$0.00")]
    [DataRow(9.9, "$9.90")]
    [DataRow(1000.005, "$1000.00")]
    public void FormatCurrency_VariousAmounts_ReturnsExpected(double amount, string expected)
    {
        var result = _formatter.FormatCurrency((decimal)amount);

        Assert.AreEqual(expected, result);
    }
}

